phase3.solution:
data class Product(val name: String, val price: Double, val category: String)

fun main() {
    val products = listOf(
        Product("Laptop", 999.99, "Electronics"),
        Product("Book", 29.99, "Education"),
        Product("Phone", 699.99, "Electronics"),
        Product("Pen", 1.99, "Education")
    )

    // map
    val names = products.map { it.name }
    println("Names: $names")

    // filter
    val cheap = products.filter { it.price < 50 }
    println("Under \$50: $cheap")

    // reduce
    val total = products.map { it.price }.reduce { acc, p -> acc + p }
    println("Total: $$${total}")

    // groupBy
    val byCategory = products.groupBy { it.category }
    println("By category: $byCategory")

    // flatMap (already implied, but here's an example)
    val allNames = products.flatMap { listOf(it.name) }
    println("All names: $allNames")
}
